(
  '10000000-0000-0000-0000-000000000001',
  'The Business Mogul',
  'business-mogul',
  'Treats real estate as an asset class. Every purchase is underwritten.',
  1,
  'Founder, CEO, PE partner, hedge fund manager; multi-home owner. Approaches luxury real estate with same analytical rigor as portfolio management. Evaluates through investment lens — total return potential, basis relative to replacement cost, comparable market performance, exit optionality. Typically acquiring primary or secondary residence but expects institutional-quality data. Almost always cash buyers, fast decisions once data supports thesis.',
  'Status + Asset Strategy',
  'ROI + Tax + Leverage',
  'Data, market intelligence, exclusivity',
  'Overpaying',
  '{"ageRange": "45-65", "netWorth": "$20M-$200M+", "primaryResidence": "Major financial centers (New York, Chicago, San Francisco, London, Singapore)", "purchaseType": "Secondary/tertiary or potential primary relocation", "transactionSpeed": "Fast 30-60 days", "financing": "Cash 91%+", "informationStyle": "Data-dense quantitative institutional", "trustSignals": "Comparable analysis, market positioning data, track record"}',
  '[{"factor": "Asset Appreciation", "weight": "critical", "description": "3-year and 5-year CAGR by micro-market, price trajectory vs comparable luxury markets nationally"}, {"factor": "Basis/Value", "weight": "critical", "description": "Price per sqft vs replacement cost, SP/OLP ratio indicating market efficiency"}, {"factor": "Liquidity/Exit", "weight": "high", "description": "DOM trends, transaction velocity, buyer pool depth"}, {"factor": "Privacy/Security", "weight": "high", "description": "Gated access, lot size, community exclusivity metrics"}, {"factor": "Lifestyle Amenities", "weight": "moderate", "description": "Club quality, proximity to private aviation, dining infrastructure"}, {"factor": "Design/Condition", "weight": "moderate", "description": "Prefers turnkey or new construction, avoids renovation risk"}]',
  '["CAGR by Micro-Market", "Price Per Square Foot Trends", "SP/OLP Ratio (Pricing Discipline)", "Cash Transaction Percentage", "Days on Market by Price Tier"]',
